package com.securebank.integrity;

import java.io.Serializable;

/**
 * Encapsulates the results of all device integrity checks.
 * Provides a trust score and individual check results.
 */
public class IntegrityCheckResult implements Serializable {

    private boolean rootDetected;
    private boolean emulatorDetected;
    private boolean debuggerAttached;
    private boolean appTampered;
    private boolean installedFromUntrustedSource;
    private boolean hookingFrameworkDetected;
    private boolean screenCaptureRisk;
    private boolean developerOptionsEnabled;
    private boolean usbDebuggingEnabled;

    private int trustScore; // 0-100, higher is more trusted
    private String riskLevel; // LOW, MEDIUM, HIGH, CRITICAL

    public void calculateTrustScore() {
        int score = 100;

        // Critical issues (heavy penalties)
        if (rootDetected) score -= 30;
        if (hookingFrameworkDetected) score -= 35;
        if (appTampered) score -= 40;
        if (debuggerAttached) score -= 25;

        // High-risk issues
        if (emulatorDetected) score -= 20;
        if (installedFromUntrustedSource) score -= 15;

        // Medium-risk issues
        if (usbDebuggingEnabled) score -= 5;
        if (developerOptionsEnabled) score -= 3;
        if (screenCaptureRisk) score -= 2;

        this.trustScore = Math.max(0, score);

        if (trustScore >= 80) {
            riskLevel = "LOW";
        } else if (trustScore >= 60) {
            riskLevel = "MEDIUM";
        } else if (trustScore >= 30) {
            riskLevel = "HIGH";
        } else {
            riskLevel = "CRITICAL";
        }
    }

    /**
     * Determines if the device is safe enough for financial transactions.
     * Blocks on critical integrity failures.
     */
    public boolean isSafeForTransactions() {
        // Hard blocks: these always prevent transactions
        if (appTampered || hookingFrameworkDetected || debuggerAttached) {
            return false;
        }
        // Score-based threshold
        return trustScore >= 50;
    }

    /**
     * Determines if the device is safe enough for viewing balance (lower bar).
     */
    public boolean isSafeForBalanceView() {
        if (appTampered || hookingFrameworkDetected) {
            return false;
        }
        return trustScore >= 30;
    }

    /**
     * Returns a user-friendly message describing detected risks.
     */
    public String getUserMessage() {
        StringBuilder sb = new StringBuilder();
        if (rootDetected) {
            sb.append("• Your device appears to be rooted. This increases security risk.\n");
        }
        if (emulatorDetected) {
            sb.append("• This appears to be an emulated device.\n");
        }
        if (debuggerAttached) {
            sb.append("• A debugger is attached to this application.\n");
        }
        if (appTampered) {
            sb.append("• The application may have been tampered with.\n");
        }
        if (hookingFrameworkDetected) {
            sb.append("• A code injection framework was detected.\n");
        }
        if (installedFromUntrustedSource) {
            sb.append("• This app was not installed from an official app store.\n");
        }
        if (sb.length() == 0) {
            return "Device integrity checks passed.";
        }
        return "Security concerns detected:\n" + sb.toString();
    }

    // Getters and setters

    public boolean isRootDetected() { return rootDetected; }
    public void setRootDetected(boolean rootDetected) { this.rootDetected = rootDetected; }

    public boolean isEmulatorDetected() { return emulatorDetected; }
    public void setEmulatorDetected(boolean emulatorDetected) { this.emulatorDetected = emulatorDetected; }

    public boolean isDebuggerAttached() { return debuggerAttached; }
    public void setDebuggerAttached(boolean debuggerAttached) { this.debuggerAttached = debuggerAttached; }

    public boolean isAppTampered() { return appTampered; }
    public void setAppTampered(boolean appTampered) { this.appTampered = appTampered; }

    public boolean isInstalledFromUntrustedSource() { return installedFromUntrustedSource; }
    public void setInstalledFromUntrustedSource(boolean installedFromUntrustedSource) {
        this.installedFromUntrustedSource = installedFromUntrustedSource;
    }

    public boolean isHookingFrameworkDetected() { return hookingFrameworkDetected; }
    public void setHookingFrameworkDetected(boolean hookingFrameworkDetected) {
        this.hookingFrameworkDetected = hookingFrameworkDetected;
    }

    public boolean isScreenCaptureRisk() { return screenCaptureRisk; }
    public void setScreenCaptureRisk(boolean screenCaptureRisk) { this.screenCaptureRisk = screenCaptureRisk; }

    public boolean isDeveloperOptionsEnabled() { return developerOptionsEnabled; }
    public void setDeveloperOptionsEnabled(boolean developerOptionsEnabled) {
        this.developerOptionsEnabled = developerOptionsEnabled;
    }

    public boolean isUsbDebuggingEnabled() { return usbDebuggingEnabled; }
    public void setUsbDebuggingEnabled(boolean usbDebuggingEnabled) {
        this.usbDebuggingEnabled = usbDebuggingEnabled;
    }

    public int getTrustScore() { return trustScore; }
    public String getRiskLevel() { return riskLevel; }
}


