package com.securebank.transaction;

import java.math.BigDecimal;

public class TransactionRequest {
    private String transactionId;
    private String fromAccountId;
    private String toAccountId;
    private BigDecimal amount;
    private String currency;
    private String description;
    private String authToken;

    // Device integrity metadata sent to server
    private int deviceTrustScore;
    private String deviceRiskLevel;
    private boolean rootDetected;
    private boolean emulatorDetected;
    private String playIntegrityToken;

    public TransactionRequest(String fromAccountId, String toAccountId,
                              BigDecimal amount, String currency,
                              String description, String authToken) {
        this.fromAccountId = fromAccountId;
        this.toAccountId = toAccountId;
        this.amount = amount;
        this.currency = currency;
        this.description = description;
        this.authToken = authToken;
    }

    // Getters and setters
    public String getTransactionId() { return transactionId; }
    public void setTransactionId(String transactionId) { this.transactionId = transactionId; }

    public String getFromAccountId() { return fromAccountId; }
    public String getToAccountId() { return toAccountId; }
    public BigDecimal getAmount() { return amount; }
    public String getCurrency() { return currency; }
    public String getDescription() { return description; }
    public String getAuthToken() { return authToken; }

    public int getDeviceTrustScore() { return deviceTrustScore; }
    public void setDeviceTrustScore(int deviceTrustScore) { this.deviceTrustScore = deviceTrustScore; }

    public String getDeviceRiskLevel() { return deviceRiskLevel; }
    public void setDeviceRiskLevel(String deviceRiskLevel) { this.deviceRiskLevel = deviceRiskLevel; }

    public boolean isRootDetected() { return rootDetected; }
    public void setRootDetected(boolean rootDetected) { this.rootDetected = rootDetected; }

    public boolean isEmulatorDetected() { return emulatorDetected; }
    public void setEmulatorDetected(boolean emulatorDetected) { this.emulatorDetected = emulatorDetected; }

    public String getPlayIntegrityToken() { return playIntegrityToken; }
    public void setPlayIntegrityToken(String playIntegrityToken) { this.playIntegrityToken = playIntegrityToken; }
}


