package com.securebank.ui;

import android.app.Activity;
import android.app.AlertDialog;
import android.os.Bundle;
import android.view.WindowManager;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;

import com.securebank.integrity.DeviceIntegrityManager;
import com.securebank.integrity.IntegrityCheckResult;
import com.securebank.transaction.BalanceResult;
import com.securebank.transaction.SecureTransactionService;
import com.securebank.transaction.TransactionRequest;
import com.securebank.transaction.TransactionResult;

import java.math.BigDecimal;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

/**
 * Main banking activity with screen protection and integrity-aware UI.
 */
public class SecureBankActivity extends Activity {

    private SecureTransactionService transactionService;
    private DeviceIntegrityManager integrityManager;
    private ExecutorService executor;

    private TextView balanceTextView;
    private TextView securityStatusTextView;
    private EditText recipientEditText;
    private EditText amountEditText;
    private Button transferButton;
    private Button refreshBalanceButton;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        // Prevent screenshots and screen recording for sensitive financial data
        getWindow().setFlags(
                WindowManager.LayoutParams.FLAG_SECURE,
                WindowManager.LayoutParams.FLAG_SECURE
        );

        // Prevent the activity from appearing in recent apps screenshots
        getWindow().addFlags(WindowManager.LayoutParams.FLAG_SECURE);

        transactionService = new SecureTransactionService(this);
        integrityManager = new DeviceIntegrityManager(this);
        executor = Executors.newSingleThreadExecutor();

        // Perform startup integrity check
        performStartupIntegrityCheck();

        setupUI();
    }

    private void setupUI() {
        // In production, inflate from layout XML
        // Simplified for demonstration

        balanceTextView = new TextView(this);
        securityStatusTextView = new TextView(this);
        recipientEditText = new EditText(this);
        amountEditText = new EditText(this);
        transferButton = new Button(this);
        refreshBalanceButton = new Button(this);

        transferButton.setText("Transfer Funds");
        refreshBalanceButton.setText("Refresh Balance");

        transferButton.setOnClickListener(v -> initiateTransfer());
        refreshBalanceButton.setOnClickListener(v -> refreshBalance());
    }

    /**
     * Performs integrity check at app startup and warns user of risks.
     */
    private void performStartupIntegrityCheck() {
        executor.execute(() -> {
            IntegrityCheckResult result = integrityManager.performFullIntegrityCheck();

            runOnUiThread(() -> {
                if ("CRITICAL".equals(result.getRiskLevel())) {
                    // Show blocking dialog for critical issues
                    new AlertDialog.Builder(this)
                            .setTitle("Security Alert")
                            .setMessage("This device does not meet the security requirements "
                                    + "for banking operations.\n\n"
                                    + result.getUserMessage()
                                    + "\nPlease use a secure device to access your account.")
                            .setCancelable(false)
                            .setPositiveButton("Exit", (dialog, which) -> finish())
                            .show();
                } else if ("HIGH".equals(result.getRiskLevel())) {
                    // Show warning but allow limited functionality
                    new AlertDialog.Builder(this)
                            .setTitle("Security Warning")
                            .setMessage("Security concerns were detected on this device.\n\n"
                                    + result.getUserMessage()
                                    + "\nSome features may be restricted.")
                            .setPositiveButton("I Understand", null)
                            .show();
                    updateSecurityStatus(result);
                } else if ("MEDIUM".equals(result.getRiskLevel())) {
                    updateSecurityStatus(result);
                } else {
                    securityStatusTextView.setText("✓ Device security verified");
                }
            });
        });
    }

    private void updateSecurityStatus(IntegrityCheckResult result) {
        securityStatusTextView.setText(
                "Security Level: " + result.getRiskLevel()
                        + " (Score: " + result.getTrustScore() + "/100)");
    }

    /**
     * Initiates a fund transfer with integrity checks.
     */
    private void initiateTransfer() {
        String recipient = recipientEditText.getText().toString().trim();
        String amountStr = amountEditText.getText().toString().trim();

        if (recipient.isEmpty() || amountStr.isEmpty()) {
            Toast.makeText(this, "Please fill in all fields", Toast.LENGTH_SHORT).show();
            return;
        }

        BigDecimal amount;
        try {
            amount = new BigDecimal(amountStr);
            if (amount.compareTo(BigDecimal.ZERO) <= 0) {
                Toast.makeText(this, "Amount must be positive", Toast.LENGTH_SHORT).show();
                return;
            }
        } catch (NumberFormatException e) {
            Toast.makeText(this, "Invalid amount", Toast.LENGTH_SHORT).show();
            return;
        }

        transferButton.setEnabled(false);
        transferButton.setText("Processing...");

        executor.execute(() -> {
            TransactionRequest request = new TransactionRequest(
                    "MY_ACCOUNT_ID",
                    recipient,
                    amount,
                    "USD",
                    "Mobile transfer",
                    "AUTH_TOKEN_HERE" // In production, from secure token storage
            );

            TransactionResult result = transactionService.processTransaction(request);

            runOnUiThread(() -> {
                transferButton.setEnabled(true);
                transferButton.setText("Transfer Funds");

                switch (result.getStatus()) {
                    case SUCCESS:
                        new AlertDialog.Builder(this)
                                .setTitle("Transfer Successful")
                                .setMessage("Transaction ID: " + result.getTransactionId()
                                        + "\n" + result.getMessage())
                                .setPositiveButton("OK", null)
                                .show();
                        refreshBalance();
                        break;

                    case BLOCKED:
                        new AlertDialog.Builder(this)
                                .setTitle("Transfer Blocked")
                                .setMessage(result.getMessage())
                                .setPositiveButton("OK", null)
                                .show();
                        break;

                    case REQUIRES_ADDITIONAL_VERIFICATION:
                        new AlertDialog.Builder(this)
                                .setTitle("Additional Verification Required")
                                .setMessage(result.getMessage()
                                        + "\n\nPlease complete verification to proceed.")
                                .setPositiveButton("Verify", (dialog, which) -> {
                                    // Launch additional verification flow
                                    // (e.g., biometric, OTP, etc.)
                                })
                                .setNegativeButton("Cancel", null)
                                .show();
                        break;

                    case ERROR:
                    default:
                        Toast.makeText(this, result.getMessage(),
                                Toast.LENGTH_LONG).show();
                        break;
                }
            });
        });
    }

    /**
     * Refreshes the account balance with integrity checks.
     */
    private void refreshBalance() {
        refreshBalanceButton.setEnabled(false);

        executor.execute(() -> {
            BalanceResult result = transactionService.getAccountBalance(
                    "MY_ACCOUNT_ID", "AUTH_TOKEN_HERE");

            runOnUiThread(() -> {
                refreshBalanceButton.setEnabled(true);

                if (result.isSuccess()) {
                    balanceTextView.setText("Balance: $" + result.getBalance().toPlainString());

                    // Ensure screen protection if flagged
                    if (result.isScreenProtectionRequired()) {
                        getWindow().setFlags(
                                WindowManager.LayoutParams.FLAG_SECURE,
                                WindowManager.LayoutParams.FLAG_SECURE);
                    }

                    if (result.getMessage() != null) {
                        Toast.makeText(this, result.getMessage(),
                                Toast.LENGTH_LONG).show();
                    }
                } else {
                    balanceTextView.setText("Balance: Unavailable");
                    new AlertDialog.Builder(this)
                            .setTitle("Cannot Display Balance")
                            .setMessage(result.getMessage())
                            .setPositiveButton("OK", null)
                            .show();
                }
            });
        });
    }

    @Override
    protected void onResume() {
        super.onResume();
        // Re-check integrity when app comes to foreground
        // (user might have enabled USB debugging, attached debugger, etc.)
        executor.execute(() -> {
            IntegrityCheckResult result = integrityManager.performQuickIntegrityCheck();
            runOnUiThread(() -> {
                if (!result.isSafeForBalanceView()) {
                    balanceTextView.setText("Balance: Hidden");
                    transferButton.setEnabled(false);
                    Toast.makeText(this,
                            "Security status changed. Some features are restricted.",
                            Toast.LENGTH_LONG).show();
                }
            });
        });
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
        if (executor != null && !executor.isShutdown()) {
            executor.shutdown();
        }
    }
}